}

.el-checkbox__original {
  opacity: 0;
  outline: none;
  position: absolute;
  margin: 0;
  width: 0;
  height: 0;
  z-index: -1;
}

.el-checkbox__label {
  display: inline-block;
  padding-left: 8px;
  line-height: 1;
  font-size: var(--el-checkbox-font-size);
}

.el-checkbox.el-checkbox--large {
  height: 40px;
}
.el-checkbox.el-checkbox--large .el-checkbox__label {
  font-size: 14px;
